LOGIN_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Pico Bit Login</title>\n  <link rel=\"stylesheet\" href=\"/assets/portal.css\">\n</head>\n<body class=\"login-page\">\n  <div class=\"bg-grid\"></div>\n  <main class=\"login-shell\">\n    <section class=\"login card\">\n      <p class=\"eyebrow\">secure injector</p>\n      <h1>Sign in to Pico Bit</h1>\n      <p class=\"lede\">\n        Join the <strong>{{ap_ssid}}</strong> access point, then sign in with the injector\n        credentials baked into the firmware.\n      </p>\n      <div class=\"notice {{message_class}}\">{{message}}</div>\n      <form action=\"/login\" method=\"post\" class=\"login__form\">\n        <label class=\"field\">\n          <span>Username</span>\n          <input name=\"username\" autocomplete=\"username\" value=\"{{username}}\" required>\n        </label>\n        <label class=\"field\">\n          <span>Password</span>\n          <input name=\"password\" type=\"password\" autocomplete=\"current-password\" required>\n        </label>\n        <button class=\"button button--wide\" type=\"submit\">Unlock injector</button>\n      </form>\n    </section>\n  </main>\n</body>\n</html>\n"

INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Pico Bit Injector</title>\n  <link rel=\"stylesheet\" href=\"/assets/portal.css\">\n</head>\n<body class=\"portal\">\n  <div class=\"bg-orb bg-orb--left\"></div>\n  <div class=\"bg-orb bg-orb--right\"></div>\n  <main class=\"shell\">\n    <header class=\"hero card\">\n      <div class=\"hero__copy\">\n        <p class=\"eyebrow\">pico-bit injector</p>\n        <h1>Shape the payload. Fire it from the browser.</h1>\n        <p class=\"lede\">\n          The Pico 2 W exposes a local control plane for <code>payload.dd</code> with\n          validation, run controls, and live device metadata.\n        </p>\n      </div>\n      <div class=\"hero__stats\">\n        <div class=\"stat\">\n          <span class=\"stat__label\">Access point</span>\n          <strong class=\"stat__value\" data-bind=\"ap_ssid\">picoBit</strong>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat__label\">AP password</span>\n          <strong class=\"stat__value stat__value--mono\" data-bind=\"ap_password\">88888888</strong>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat__label\">Portal auth</span>\n          <strong class=\"stat__value\" data-bind=\"auth_label\">Enabled</strong>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat__label\">Runtime mode</span>\n          <strong class=\"stat__value\" data-bind=\"mode_label\">Safe mode</strong>\n        </div>\n      </div>\n    </header>\n\n    <section class=\"workspace\">\n      <article class=\"editor card\">\n        <div class=\"editor__bar\">\n          <div class=\"traffic\">\n            <span></span><span></span><span></span>\n          </div>\n          <div class=\"editor__file\">payload.dd</div>\n          <div class=\"editor__meta\">\n            <span class=\"chip chip--tone\" data-bind=\"mode_short\">Unsafe blocked</span>\n            <span class=\"chip\" data-bind=\"payload_state\">Saved on device</span>\n          </div>\n        </div>\n\n        <div class=\"notice notice--hidden\" id=\"notice\"></div>\n\n        <label class=\"editor__label\" for=\"payload\">Payload editor</label>\n        <textarea\n          id=\"payload\"\n          class=\"editor__input\"\n          spellcheck=\"false\"\n          autocapitalize=\"off\"\n          autocomplete=\"off\"\n          autocorrect=\"off\"\n          placeholder=\"REM Write your payload here\"\n        ></textarea>\n\n        <div class=\"editor__footer\">\n          <p class=\"editor__note\" data-bind=\"mode_description\">\n            Safe mode is active, so unsupported unsafe features stay blocked.\n          </p>\n          <div class=\"editor__actions\">\n            <button class=\"button button--ghost\" id=\"refresh\" type=\"button\">Reload</button>\n            <button class=\"button button--ghost\" id=\"save\" type=\"button\">Save</button>\n            <button class=\"button\" id=\"run\" type=\"button\">Save and run</button>\n          </div>\n        </div>\n      </article>\n\n      <aside class=\"rail\">\n        <section class=\"card panel\">\n          <h2>Flight deck</h2>\n          <p>\n            The portal stays available while the payload engine runs, so you can correct scripts\n            without reflashing the board.\n          </p>\n          <ul class=\"list\">\n            <li>Boot payload seeded if the file is missing</li>\n            <li>Validation happens before every run</li>\n            <li>Cookie login protects the injector</li>\n            <li>CORS can be enabled for trusted tooling</li>\n          </ul>\n        </section>\n\n        <section class=\"card panel\">\n          <h2>Status</h2>\n          <dl class=\"meta\">\n            <div>\n              <dt>Payload file</dt>\n              <dd>payload.dd</dd>\n            </div>\n            <div>\n              <dt>Seeded this boot</dt>\n              <dd data-bind=\"seeded\">No</dd>\n            </div>\n            <div>\n              <dt>Host HID</dt>\n              <dd data-bind=\"hid_state\">Waiting</dd>\n            </div>\n          </dl>\n          <form action=\"/logout\" method=\"post\" class=\"logout\">\n            <button class=\"button button--ghost button--wide\" type=\"submit\">Sign out</button>\n          </form>\n        </section>\n      </aside>\n    </section>\n  </main>\n\n  <script src=\"/assets/portal.js\"></script>\n</body>\n</html>\n"

PORTAL_CSS = ":root {\n  color-scheme: light;\n  --ink: #122033;\n  --muted: #5d6b7b;\n  --line: rgba(18, 32, 51, 0.12);\n  --soft: rgba(255, 255, 255, 0.78);\n  --panel: rgba(255, 255, 255, 0.9);\n  --panel-strong: rgba(255, 255, 255, 0.96);\n  --accent: #0f9d7f;\n  --accent-deep: #0b6c59;\n  --accent-warm: #ff8f59;\n  --danger: #cb3a31;\n  --shadow: 0 28px 70px rgba(25, 39, 61, 0.12);\n  --mono: \"SFMono-Regular\", \"Cascadia Mono\", \"Menlo\", monospace;\n  --sans: \"Avenir Next\", \"Segoe UI\", sans-serif;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nhtml,\nbody {\n  margin: 0;\n  min-height: 100%;\n  color: var(--ink);\n  font-family: var(--sans);\n  background:\n    radial-gradient(circle at top left, rgba(255, 212, 182, 0.45), transparent 32%),\n    radial-gradient(circle at top right, rgba(125, 227, 205, 0.35), transparent 30%),\n    linear-gradient(180deg, #f8fbff 0%, #f5f0e8 100%);\n}\n\nbody {\n  position: relative;\n  overflow-x: hidden;\n}\n\ncode {\n  font-family: var(--mono);\n}\n\n.bg-orb,\n.bg-grid {\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n}\n\n.bg-orb--left::before,\n.bg-orb--right::before {\n  content: \"\";\n  position: absolute;\n  width: 24rem;\n  height: 24rem;\n  border-radius: 999px;\n  filter: blur(36px);\n  opacity: 0.45;\n}\n\n.bg-orb--left::before {\n  top: -8rem;\n  left: -7rem;\n  background: rgba(255, 151, 106, 0.48);\n}\n\n.bg-orb--right::before {\n  top: -7rem;\n  right: -5rem;\n  background: rgba(42, 193, 157, 0.35);\n}\n\n.bg-grid {\n  background-image:\n    linear-gradient(rgba(18, 32, 51, 0.04) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(18, 32, 51, 0.04) 1px, transparent 1px);\n  background-size: 28px 28px;\n  mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.25), transparent 80%);\n}\n\n.shell,\n.login-shell {\n  position: relative;\n  z-index: 1;\n  width: min(1200px, calc(100% - 2rem));\n  margin: 0 auto;\n  padding: 1.4rem 0 3rem;\n}\n\n.card {\n  backdrop-filter: blur(18px);\n  background: var(--panel);\n  border: 1px solid rgba(255, 255, 255, 0.48);\n  border-radius: 2rem;\n  box-shadow: var(--shadow);\n}\n\n.hero {\n  display: grid;\n  gap: 1.5rem;\n  padding: 1.8rem;\n}\n\n.hero h1,\n.login h1 {\n  margin: 0.35rem 0 0;\n  font-size: clamp(2.5rem, 5vw, 4.4rem);\n  line-height: 0.96;\n  letter-spacing: -0.06em;\n}\n\n.eyebrow {\n  margin: 0;\n  text-transform: uppercase;\n  letter-spacing: 0.16em;\n  font-size: 0.72rem;\n  font-weight: 800;\n  color: var(--accent-deep);\n}\n\n.lede {\n  margin: 1rem 0 0;\n  max-width: 42rem;\n  color: var(--muted);\n  line-height: 1.75;\n  font-size: 1rem;\n}\n\n.hero__stats {\n  display: grid;\n  gap: 0.85rem;\n}\n\n.stat,\n.panel,\n.editor {\n  background: var(--panel-strong);\n}\n\n.stat {\n  border: 1px solid var(--line);\n  border-radius: 1.2rem;\n  padding: 1rem 1.1rem;\n}\n\n.stat__label,\n.meta dt,\n.field span,\n.editor__label {\n  display: block;\n  margin-bottom: 0.35rem;\n  font-size: 0.76rem;\n  text-transform: uppercase;\n  letter-spacing: 0.12em;\n  color: var(--muted);\n  font-weight: 700;\n}\n\n.stat__value,\n.meta dd {\n  margin: 0;\n  font-size: 1rem;\n  font-weight: 800;\n}\n\n.stat__value--mono,\n.editor__file {\n  font-family: var(--mono);\n}\n\n.workspace {\n  display: grid;\n  gap: 1.2rem;\n  margin-top: 1.2rem;\n}\n\n.editor {\n  padding: 1.2rem;\n  border: 1px solid rgba(18, 32, 51, 0.1);\n}\n\n.editor__bar,\n.editor__footer,\n.editor__actions,\n.editor__meta {\n  display: flex;\n  gap: 0.75rem;\n  align-items: center;\n  flex-wrap: wrap;\n}\n\n.editor__bar {\n  justify-content: space-between;\n  margin-bottom: 1rem;\n}\n\n.traffic {\n  display: flex;\n  gap: 0.4rem;\n}\n\n.traffic span {\n  width: 0.7rem;\n  height: 0.7rem;\n  border-radius: 999px;\n  background: linear-gradient(180deg, #ffd3a6, #ff9757);\n}\n\n.editor__file,\n.chip {\n  border-radius: 999px;\n  padding: 0.55rem 0.9rem;\n  background: rgba(18, 32, 51, 0.06);\n  font-size: 0.8rem;\n  font-weight: 700;\n}\n\n.chip--tone {\n  background: rgba(15, 157, 127, 0.12);\n  color: var(--accent-deep);\n}\n\n.editor__input,\n.field input {\n  width: 100%;\n  border: 1px solid rgba(18, 32, 51, 0.08);\n  background: linear-gradient(180deg, rgba(255, 255, 255, 0.96), rgba(247, 247, 243, 0.96));\n  color: var(--ink);\n  outline: none;\n}\n\n.editor__input {\n  min-height: 33rem;\n  resize: vertical;\n  border-radius: 1.6rem;\n  padding: 1.25rem;\n  font: 0.93rem/1.72 var(--mono);\n  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.8);\n}\n\n.editor__input:focus,\n.field input:focus {\n  border-color: rgba(15, 157, 127, 0.6);\n  box-shadow: 0 0 0 0.22rem rgba(15, 157, 127, 0.12);\n}\n\n.editor__footer {\n  justify-content: space-between;\n  margin-top: 1rem;\n}\n\n.editor__note,\n.panel p,\n.list,\n.login .lede {\n  color: var(--muted);\n  line-height: 1.7;\n}\n\n.editor__note {\n  margin: 0;\n  max-width: 34rem;\n}\n\n.button {\n  appearance: none;\n  border: 0;\n  cursor: pointer;\n  border-radius: 1rem;\n  padding: 0.95rem 1.2rem;\n  font: inherit;\n  font-weight: 800;\n  color: white;\n  background: linear-gradient(180deg, var(--accent), var(--accent-deep));\n  box-shadow: 0 12px 24px rgba(15, 109, 89, 0.18);\n  transition: transform 0.12s ease, box-shadow 0.12s ease, opacity 0.12s ease;\n}\n\n.button:hover {\n  transform: translateY(-1px);\n  box-shadow: 0 18px 28px rgba(15, 109, 89, 0.22);\n}\n\n.button:active {\n  transform: translateY(1px);\n}\n\n.button:disabled {\n  cursor: wait;\n  opacity: 0.72;\n}\n\n.button--ghost {\n  color: var(--ink);\n  background: rgba(18, 32, 51, 0.05);\n  box-shadow: none;\n}\n\n.button--wide {\n  width: 100%;\n}\n\n.rail {\n  display: grid;\n  gap: 1rem;\n}\n\n.panel {\n  padding: 1.35rem;\n  border: 1px solid rgba(18, 32, 51, 0.08);\n}\n\n.panel h2 {\n  margin: 0 0 0.7rem;\n  font-size: 1.1rem;\n  letter-spacing: -0.03em;\n}\n\n.list {\n  margin: 0;\n  padding-left: 1.1rem;\n}\n\n.meta {\n  display: grid;\n  gap: 0.8rem;\n  margin: 0;\n}\n\n.meta div {\n  padding: 0.75rem 0.85rem;\n  border: 1px solid rgba(18, 32, 51, 0.08);\n  border-radius: 1rem;\n  background: rgba(255, 255, 255, 0.74);\n}\n\n.logout {\n  margin-top: 1rem;\n}\n\n.notice {\n  border-radius: 1rem;\n  padding: 0.95rem 1rem;\n  font-size: 0.95rem;\n  line-height: 1.5;\n  margin-bottom: 1rem;\n  border: 1px solid rgba(18, 32, 51, 0.08);\n  background: rgba(255, 255, 255, 0.66);\n}\n\n.notice--hidden {\n  display: none;\n}\n\n.notice--success {\n  background: rgba(42, 193, 157, 0.13);\n  border-color: rgba(42, 193, 157, 0.24);\n}\n\n.notice--error {\n  background: rgba(203, 58, 49, 0.1);\n  border-color: rgba(203, 58, 49, 0.2);\n}\n\n.notice--quiet {\n  background: rgba(18, 32, 51, 0.05);\n}\n\n.login-page {\n  display: grid;\n  place-items: center;\n}\n\n.login-shell {\n  min-height: 100vh;\n  display: grid;\n  place-items: center;\n}\n\n.login {\n  width: min(32rem, 100%);\n  padding: 1.8rem;\n}\n\n.login__form {\n  display: grid;\n  gap: 1rem;\n  margin-top: 1.4rem;\n}\n\n.field input {\n  padding: 0.95rem 1rem;\n  border-radius: 1rem;\n  font: inherit;\n}\n\n@media (min-width: 980px) {\n  .hero {\n    grid-template-columns: 1.4fr 0.95fr;\n    align-items: end;\n  }\n\n  .workspace {\n    grid-template-columns: minmax(0, 1.65fr) minmax(18rem, 0.9fr);\n  }\n}\n\n@media (max-width: 760px) {\n  .shell,\n  .login-shell {\n    width: min(100% - 1rem, 100%);\n  }\n\n  .hero,\n  .editor,\n  .panel,\n  .login {\n    border-radius: 1.5rem;\n  }\n\n  .editor__footer {\n    align-items: stretch;\n  }\n\n  .editor__actions {\n    width: 100%;\n  }\n\n  .editor__actions .button {\n    flex: 1;\n  }\n}\n"

PORTAL_JS = "const notice = document.getElementById('notice');\nconst payloadField = document.getElementById('payload');\nconst saveButton = document.getElementById('save');\nconst runButton = document.getElementById('run');\nconst refreshButton = document.getElementById('refresh');\n\nfunction setNotice(message, tone = 'quiet') {\n  if (!notice) {\n    return;\n  }\n  if (!message) {\n    notice.className = 'notice notice--hidden';\n    notice.textContent = '';\n    return;\n  }\n  notice.className = `notice notice--${tone}`;\n  notice.textContent = message;\n}\n\nfunction setBoundText(name, value) {\n  document.querySelectorAll(`[data-bind=\"${name}\"]`).forEach((node) => {\n    node.textContent = value;\n  });\n}\n\nfunction setBusy(button, busy) {\n  if (!button) {\n    return;\n  }\n  button.disabled = busy;\n}\n\nasync function requestJson(path, options = {}) {\n  const response = await fetch(path, {\n    credentials: 'same-origin',\n    headers: {\n      'Content-Type': 'application/json',\n      ...options.headers,\n    },\n    ...options,\n  });\n\n  if (response.status === 401) {\n    window.location.href = '/login';\n    throw new Error('Unauthorized');\n  }\n\n  const data = await response.json().catch(() => ({}));\n  if (!response.ok) {\n    throw new Error(data.message || `Request failed with ${response.status}`);\n  }\n  return data;\n}\n\nasync function loadBootstrap() {\n  const state = await requestJson('/api/bootstrap');\n  payloadField.value = state.payload || '';\n  setBoundText('ap_ssid', state.ap_ssid);\n  setBoundText('ap_password', state.ap_password || 'Open network');\n  setBoundText('mode_label', state.mode_label);\n  setBoundText('mode_short', state.mode_short);\n  setBoundText('mode_description', state.mode_description);\n  setBoundText('seeded', state.seeded ? 'Yes' : 'No');\n  setBoundText('hid_state', state.keyboard_ready ? 'Ready' : 'Waiting');\n  setBoundText('auth_label', state.auth_enabled ? 'Enabled' : 'Disabled');\n  setBoundText('payload_state', state.seeded ? 'Seeded on boot' : 'Saved on device');\n  setNotice(state.message || '', state.notice || 'quiet');\n}\n\nasync function savePayload() {\n  setBusy(saveButton, true);\n  try {\n    const result = await requestJson('/api/payload', {\n      method: 'POST',\n      body: JSON.stringify({ payload: payloadField.value }),\n    });\n    setBoundText('payload_state', 'Saved on device');\n    setNotice(result.message, result.notice || 'success');\n  } catch (error) {\n    setNotice(error.message, 'error');\n  } finally {\n    setBusy(saveButton, false);\n  }\n}\n\nasync function runPayload() {\n  setBusy(runButton, true);\n  try {\n    const result = await requestJson('/api/run', {\n      method: 'POST',\n      body: JSON.stringify({ payload: payloadField.value, save: true }),\n    });\n    setBoundText('hid_state', 'Ready');\n    setNotice(result.message, result.notice || 'success');\n  } catch (error) {\n    setNotice(error.message, 'error');\n  } finally {\n    setBusy(runButton, false);\n  }\n}\n\nif (refreshButton) {\n  refreshButton.addEventListener('click', () => {\n    loadBootstrap().catch((error) => setNotice(error.message, 'error'));\n  });\n}\n\nif (saveButton) {\n  saveButton.addEventListener('click', () => {\n    savePayload();\n  });\n}\n\nif (runButton) {\n  runButton.addEventListener('click', () => {\n    runPayload();\n  });\n}\n\nloadBootstrap().catch((error) => setNotice(error.message, 'error'));\n"

